const input = $input.first().json;

const tenantId    = String(input.tenant_id   || '').trim();
const businessId  = String(input.business_id || '').trim();
const productName = String(input.product_name || '').trim();
const imageUrl    = String(input.image_url    || '').trim();
const mimeType    = String(input.mime_type    || 'image/jpeg').trim();

// Parse price — accept number, string like '45000', '₦45,000', '45k'
let price = null;
let priceLabel = null;
const rawPrice = input.price;
if (rawPrice !== null && rawPrice !== undefined && rawPrice !== '') {
  const cleaned = String(rawPrice).replace(/[₦,\s]/g, '').replace(/k$/i, '000');
  const parsed = parseFloat(cleaned);
  if (!isNaN(parsed) && parsed > 0) {
    price = parsed;
    // Build a clean label
    priceLabel = '₦' + parsed.toLocaleString('en-NG');
  }
}

if (!tenantId)    throw new Error('Missing tenant_id');
if (!productName) throw new Error('Missing product_name');
if (!imageUrl)    throw new Error('Missing image_url');

const slug = productName.toLowerCase().replace(/[^a-z0-9]/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');
const ext  = mimeType.split('/')[1] || 'jpg';
// Use business_id in path if available, else tenant_id only
const pathPrefix = businessId ? tenantId + '/' + businessId : tenantId;
const objectKey = pathPrefix + '/products/' + slug + '.' + ext;

return [{
  json: {
    tenant_id:    tenantId,
    business_id:  businessId || null,
    product_name: productName,
    image_url:    imageUrl,
    mime_type:    mimeType,
    price:        price,
    price_label:  priceLabel,
    object_key:   objectKey
  }
}];

const preserved = $('Preserve Fields').first().json;

const baseUrl   = '[URL]';
const objectKey = preserved.object_key;
const minioUrl  = baseUrl + '/mysquad-assets/' + objectKey;

return [{
  json: {
    tenant_id:    preserved.tenant_id,
    business_id:  preserved.business_id || null,
    product_name: preserved.product_name,
    minio_url:    minioUrl,
    minio_key:    objectKey,
    mime_type:    preserved.mime_type,
    price:        preserved.price || null,
    price_label:  preserved.price_label || null,
    upload_source: 'owner_chat'
  }
}];

const row = $input.first().json;

return [{
  json: {
    success:      true,
    action:       row.action || 'saved',
    product_name: row.product_name,
    minio_url:    row.minio_url,
    price:        row.price || null,
    price_label:  row.price_label || null
  }
}];
